from pydantic_ai import Agent, tool
import requests

class ApprovalAgent(Agent):
    def __init__(self):
        super().__init__(
            model='gpt-4o',
            result_model=dict,
            instructions='Request human approval for high-value orders'
        )

    @tool
    def request_approval(self, order_id: str, amount: float) -> dict:
        if amount > 1000:
            response = requests.post(
                'https://approval-api.example.com/review',
                json={'order_id': order_id, 'amount': amount}
            )
            return {'approved': response.json()['approved'], 'reviewer': response.json()['user']}
        return {'approved': True, 'reviewer': 'auto'}

