from vex_sdk import VexValidator
from pydantic_ai import Agent

# Define Vex validator for workflow correctness
workflow_validator = VexValidator(
    name="workflow-action-validator",
    rules=[
        {
            "type": "action_correctness",
            "condition": "result.step in ['VALIDATED', 'PAID', 'SHIPPED']",
            "error_message": "Invalid workflow step detected"
        },
        {
            "type": "permission_check",
            "condition": "ctx.user.permissions.contains(result.action)",
            "error_message": "Insufficient permissions"
        }
    ]
)

class ValidatedOrchestrator(Agent):
    def __init__(self):
        super().__init__(
            model='gpt-4o',
            result_validators=[workflow_validator],
            context_providers=['user_permissions', 'transaction_state']
        )

from vex_sdk import VexValidator

idempotency_validator = VexValidator(
    name="idempotency-rollback",
    risk_profile="medium",
    rules=[
        {
            "type": "idempotency_check",
            "condition": "!self.has_side_effects(result) || self.verify_idempotent(ctx.transaction_id)",
            "rollback": {
                "type": "api_rollback",
                "endpoint": "https://api.example.com/rollback/{ctx.order_id}",
                "method": "POST"
            }
        },
        {
            "type": "duplicate_detection",
            "condition": "ctx.transaction_id not in self.seen_transactions",
            "action": "block_and_log"
        }
    ]
)

# Attach to agent
agent.result_validators.append(idempotency_validator)
